const { device_ip, device_type, operation } = $('📥 Input').first().json;
if (!device_ip || !device_type || !operation) throw new Error('device_ip, device_type und operation erforderlich');
const supported = ['mikrotik', 'vyos', 'opnsense', 'generic'];
if (!supported.includes(device_type)) throw new Error(`Nicht unterstützter Gerätetyp: ${device_type}`);
const ops = ['backup_config', 'check_health', 'get_interfaces', 'get_routes', 'reboot'];
if (!ops.includes(operation)) throw new Error(`Unbekannte Operation: ${operation}`);
return { device_ip, device_type, operation, session_id: require('crypto').randomUUID(),
  timestamp: new Date().toISOString() };

const { device_ip, device_type, operation, session_id } = $input.first().json;
return { exit_code: 'success', session_id,
  data: { device_ip, device_type, operation, result: `${operation} auf ${device_type} (${device_ip}) ausgeführt` },
  timestamp: new Date().toISOString() };
